sql:
SELECT type_id, AVG(quality) AS average_quality
FROM wine_samples
GROUP BY type_id;

SELECT *
FROM wine_types
WHERE description IS NOT NULL;

SELECT SUM(sample_id) 
FROM wine_samples 
WHERE type_id = 5;

SELECT sample_id
FROM tasting_notes
WHERE rating >= 8;

external_knowledge:
- "bottles" refer to wine samples;
- "lineage" refers to the type name and type ID of the wine;
- "sage" refers to the machine learning model that predicted the highest quality of a wine sample;
- "guardian" refers to the user who accessed the sample;
- "manner of their encounter" refers to the type of access (view, edit, etc.).

sql:
SELECT wt.type_name, wt.description
FROM wine_types wt
WHERE wt.type_id IN (SELECT DISTINCT ws.type_id FROM wine_samples ws);

SELECT DISTINCT wt.type_name
FROM wine_samples ws
INNER JOIN wine_types wt ON ws.type_id = wt.type_id;

SELECT vintage_year, COUNT(DISTINCT type_id) AS distinct_wine_types
FROM wine_samples
GROUP BY vintage_year;

SELECT sample_id, quality
FROM wine_samples
WHERE quality >= 8;

SELECT u.user_name, u.email
FROM users u
JOIN access_logs a ON u.user_id = a.user_id;

SELECT type_name
FROM wine_types
WHERE type_id = 1;

SELECT DISTINCT producer
FROM wine_samples
WHERE location = 'your_location_here';

SELECT sample_id, quality
FROM wine_samples
WHERE quality > (SELECT AVG(quality) FROM wine_samples);

SELECT tn.sample_id, u.user_name
FROM tasting_notes tn
INNER JOIN users u ON tn.taster_id = u.user_id;

SELECT producer
FROM wine_samples
WHERE alcohol = (
  SELECT MAX(alcohol)
  FROM wine_samples
);
